class ILODComponentObserver
{
public:
};

class LODComponentObservers
{
private:
	TArray<ILODComponentObserver*, ArgusContainerAllocator<2u> > m_LODComponentObservers;

public:
	void AddObserver(ILODComponentObserver* observer)
	{
		if (!observer)
		{
			return;
		}

		m_LODComponentObservers.Add(observer);
	}

	void RemoveObserver(ILODComponentObserver* observer)
	{
		if (!observer)
		{
			return;
		}

		m_LODComponentObservers.RemoveAll
		(
			[observer] (ILODComponentObserver* other)
			{
				return other == observer;
			}
		);
	}

	void Reset()
	{
		m_LODComponentObservers.Reset();
	}

private:

	friend struct LODComponent;
};
